/**
 * Rovix icon helper — professional colored SVG icons replacing emojis.
 *
 * Usage in views:  <?= rx_icon('calendar') ?>
 *                  <?= rx_icon('calendar', 'w-8 h-8') ?>          // custom size
 *                  <?= rx_icon('calendar', 'w-5 h-5', 'inline') ?> // extra wrapper classes
 *
 * Icons are Heroicons-style outlines with semantic default colors.
 */

if (! function_exists('rx_icon')) {
    function rx_icon(string $name, string $size = 'w-5 h-5', string $extra = ''): string
    {
        $icons = rx_icon_registry();

        if (! isset($icons[$name])) {
            return '';
        }

        [$color, $paths] = $icons[$name];

        return '<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.8" stroke="currentColor" '
            . 'class="' . $size . ' ' . $color . ($extra !== '' ? ' ' . $extra : '') . ' inline-block flex-shrink-0" aria-hidden="true">'
            . $paths
            . '</svg>';
    }
}

